#### 3. 后端接收凭证的程式碼（Python版）
後end 接收员工輸入的帳號和密碼，並進行簡單的處理：

```python
import sqlite3
from flask import Flask, request

app = Flask(__name__)

@app.route('/')
def captive_portal():
    # 取得用戶輸入的帳號和密碼
    username = request.args.get('username')
    password = request.args.get('password')

    # 連接到 simulated 資庫
    conn = sqlite3.connect(':memory:')
    cursor = conn.cursor()
    cursor.execute("CREATE TABLE IF NOT EXISTS guests (id INTEGER PRIMARY KEY AUTOINCREMENT, username TEXT, password TEXT)")
    cursor.execute("INSERT INTO guests (username, password) VALUES (?, ?)", (username, password))
    conn.commit()

    # 重新連接到 simulated 資庫並顯示成功拦截消息
    conn2 = sqlite3.connect(':memory:')
    cursor2 = conn2.cursor()
    cursor2.execute("SELECT COUNT(*) FROM guests WHERE username='guest' AND password='testpass';")
    result = cursor2.fetchone()

    return f"Successfully intercepted login attempt. Guest account {username} attempted to access the network."

if __name__ == '__main__':
    app.run(port=5000)
```

